import{_ as a,o as s,c as o,aB as n}from"./chunks/framework.iGRM0pMP.js";const m=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":null}'),i={name:"architecture.md"};function t(c,e,r,l,p,d){return s(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="Architecture-Overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#Architecture-Overview" aria-label="Permalink to &quot;Architecture Overview {#Architecture-Overview}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Page Info</p><ul><li><p><strong>Audience:</strong> Advanced / Contributors</p></li><li><p><strong>Prerequisites:</strong> familiarity with PlantGeom runtime APIs</p></li><li><p><strong>Time:</strong> 12 minutes</p></li><li><p><strong>Output:</strong> High-level architecture and data-flow mental model</p></li></ul></div><p>This package bridges Plant MTGs with meshes and high‑performance visualization.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OPF/OPS files ──► read_opf/read_ops ──► MTG (MultiScaleTreeGraph)</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>                                  ▼</span></span>
<span class="line"><span>                         Reference Meshes (RefMesh)</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>                                  ▼</span></span>
<span class="line"><span>                    Geometry (ref_mesh + transform)</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>                    (lazy) refmesh_to_mesh per node</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>                                  ▼</span></span>
<span class="line"><span>            Merge all meshes into a single GeometryBasics.Mesh geometry</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>                                  ▼</span></span>
<span class="line"><span>             plantviz (Makie recipe) ──► Makie Figure/Axis</span></span></code></pre></div><ul><li><p>Core types: <code>RefMesh</code> stores template geometry; <code>Geometry</code> attaches a <code>ref_mesh</code> and a <code>CoordinateTransformations.Transformation</code> (<code>Translation</code>, <code>LinearMap</code>, <code>AffineMap</code>, composed with <code>∘</code>) to an MTG node attribute <code>:geometry</code>; <code>PointMappedGeometry</code> reuses a <code>RefMesh</code> while deforming it through a concrete point map; <code>ExtrudedTubeGeometry</code> stores per-node procedural tube parameters (path/profile scaling/material/transform) and generates meshes on demand.</p></li><li><p>IO: <code>read_opf</code>/<code>read_ops</code> populate MTG nodes and scene transforms; <code>write_opf</code>/<code>write_ops</code> serialize meshes and transforms back to disk. <code>read_opf</code> stores root <code>:ref_meshes</code> as <code>Dict{Int,RefMesh}</code> keyed by OPF shape IDs (preserved as file values, typically 0-based). It supports <code>&lt;faces&gt;&lt;face&gt;...&lt;/face&gt;&lt;/faces&gt;</code> meshes (including polygon triangulation), and <code>read_ops</code> can read legacy OPS rows via <code>read_ops(...; relaxed=true, assume_scale_column=false, ...)</code>. OPS object transforms (<code>rotation</code>, <code>scale</code>, <code>inclinationAzimut</code>/<code>inclinationAngle</code>, <code>pos</code>) are applied at load time. <code>#[Archimed] ...</code> section headers are optional; missing <code>functional_group</code> values default to <code>&quot;&quot;</code> unless strict mode is requested.</p></li><li><p>Computation: meshes are computed lazily; call <code>refmesh_to_mesh</code> to materialize <code>Geometry(ref_mesh=...)</code> nodes. Point-mapped and procedural nodes (<code>PointMappedGeometry</code>, <code>ExtrudedTubeGeometry</code>) are also materialized lazily during scene merge. Matrix generation uses <code>get_transformation_matrix</code>. At render time, node meshes are merged to a single <code>GeometryBasics.Mesh</code>.</p></li><li><p>Visualization: <code>plantviz</code> builds on Makie’s ComputeGraph. It maps colors from attributes or user dictionaries via <code>get_mtg_color</code>/<code>get_color</code>/<code>get_colormap</code>, wires them as compute nodes with <code>map!</code>, and renders the merged mesh once.</p></li></ul><p>Minimal example</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PlantGeom</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">opf </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> read_opf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;test/files/simple_plant.opf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fig, ax, plt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> plantviz</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(opf)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># visualize</span></span></code></pre></div><h2 id="Color-Mapping-and-Caching" tabindex="-1">Color Mapping &amp; Caching <a class="header-anchor" href="#Color-Mapping-and-Caching" aria-label="Permalink to &quot;Color Mapping &amp;amp; Caching {#Color-Mapping-and-Caching}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input to plantviz(color=..., colormap=..., colorrange=...)</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>  get_mtg_color / get_ref_meshes_color   get_colormap</span></span>
<span class="line"><span>          │                                │</span></span>
<span class="line"><span>          ▼                                ▼</span></span>
<span class="line"><span>      get_color_range ◄──────────── optional user colorrange</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>Per-node color values (or per-refmesh/per-vertex inputs)</span></span>
<span class="line"><span>          │             ┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>          ├────────────►│ Cache: UUIDs-based attribute on MTG     │</span></span>
<span class="line"><span>          │             │ (e.g., :_cache_&lt;hash&gt;) holds Observables│</span></span>
<span class="line"><span>          ▼             └─────────────────────────────────────────┘</span></span>
<span class="line"><span> Makie plot attributes (colormap, colorrange, color per vertex)</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>        plantviz recipe renders via GeometryBasics/Makie</span></span></code></pre></div><ul><li><p>Inputs: single color, <code>Dict(&quot;RefMeshName&quot; =&gt; color)</code>, attribute symbol (e.g., <code>:z_max</code>), or per-vertex arrays. A vector of colors/symbols per node is also supported; it expands to per-face colors using the <code>face2node</code> mapping of the merged mesh.</p></li><li><p>Mapping: <code>get_colormap</code> resolves a <code>ColorScheme</code>; <code>get_color_range</code> derives or validates ranges; <code>get_color</code> maps values to colors.</p></li><li><p>Caching:</p><ul><li><p>Per-node color caches (UUID-derived Observables) for interactive updates when plotting per-node geometry.</p></li><li><p>Scene cache on the root (<code>:_scene_cache</code>) as a single-entry NamedTuple <code>(hash, mesh, face2node)</code>. The <code>hash</code> encodes the scene version and relevant options (filters). Invalidate with <code>bump_scene_version!(mtg)</code>.</p></li></ul></li></ul><h3 id="Rendering-Model-Merged-by-Default" tabindex="-1">Rendering Model (Merged by Default) <a class="header-anchor" href="#Rendering-Model-Merged-by-Default" aria-label="Permalink to &quot;Rendering Model (Merged by Default) {#Rendering-Model-Merged-by-Default}&quot;">​</a></h3><ul><li><p>Build: traverses selected nodes, transforms ref meshes, materializes node meshes if needed, and merges them into one <code>GeometryBasics.Mesh</code> for rendering. The merge is performed in a single pass for performance.</p></li><li><p>Colors: computes a single per-vertex color array and passes it to Makie. Attribute colors honor <code>colormap</code> and <code>colorrange</code>; dictionary inputs by refmesh are supported; per-vertex dictionaries pass through directly.</p></li><li><p>Mapping: <code>face2node</code> is stored alongside the merged mesh in <code>:_scene_cache</code> to map triangles back to node IDs. This enables expanding per-node color vectors to per-face arrays.</p></li><li><p>Use: <code>plantviz(opf, color=:z_max)</code>; invalidate cache after geometry/attribute changes via <code>bump_scene_version!(opf)</code>. The merged mesh and <code>face2node</code> are reused across color updates.</p></li></ul><h2 id="Key-Components" tabindex="-1">Key Components <a class="header-anchor" href="#Key-Components" aria-label="Permalink to &quot;Key Components {#Key-Components}&quot;">​</a></h2><ul><li><p><code>build_merged_mesh_with_map(mtg; ...)</code>: collects selected node meshes and returns <code>(merged::GeometryBasics.Mesh, face2node::Vector{Int})</code>. The <code>face2node</code> array maps each element of the merged mesh back to its originating node id.</p></li><li><p>Scene cache helpers:</p><ul><li><p><code>scene_version</code>, <code>bump_scene_version!</code>: version the scene to invalidate cache.</p></li><li><p><code>scene_cache_key</code>: builds a stable key for the current selection/options.</p></li><li><p><code>get_cached_scene</code>, <code>set_cached_scene!</code>: retrieve/store a single cached scene <code>(hash, mesh, face2node)</code> on the MTG root.</p></li></ul></li><li><p>PlantViz recipe (Makie): defines attributes (<code>color</code>, <code>colormap</code>, <code>colorrange</code>, etc.) and derives compute nodes with <code>map!</code> (<code>:colorant</code>, <code>:colormap_resolved</code>, <code>:colorrange_resolved</code>, <code>:index_resolved</code>). The plot calls into a helper that computes or retrieves the merged scene and computes vertex colors as needed.</p></li></ul><h2 id="Performance-Notes" tabindex="-1">Performance Notes <a class="header-anchor" href="#Performance-Notes" aria-label="Permalink to &quot;Performance Notes {#Performance-Notes}&quot;">​</a></h2><ul><li><p>Merging: performed in one pass; avoid repeated pairwise merges. Connectivity indices are reindexed with a running vertex offset.</p></li><li><p>face2node: built with a single preallocated vector, filling by contiguous slices per node to minimize allocations.</p></li><li><p>Colors: computed once per render and are not cached in the scene cache; only the merged mesh and face2node are cached to reduce invalidation churn.</p></li></ul>`,16)])])}const g=a(i,[["render",t]]);export{m as __pageData,g as default};
